import React from 'react';
import CardItem from './Carditem';
import { Button } from './Button';
import './Cards';

function Cards() {
  return (
    <div className='cards'>
      <h1> À propos </h1>
      <p> Bienvenue sur mon site ! Vous trouverez sur cette pages des ateliers sur différentes thématiques alliant le corps et l’esprit dans une optique féministe et holistique. </p>

      <h3> LES ATELIERS </h3>

      <p> <strong>Yoga Vinyasa (tous niveaux)</strong> : yoga dynamique enchaînant différents flows pour nous aider à gagner en confiance en soi, se relaxer et avoir un meilleur rapport à son corps.<br>

      </br><strong>Voyage chamanique au tambour (voyage dans le monde de l’invisible)</strong> : voyage au son du tambour dans la tradition des chamanes afin de se connecter à aux esprits de la terre, lâcher prise et comprendre ce qui se passe en nous. Chacun.e y va à son rythme ! <br>

      </br><strong>Ateliers coaching </strong> : se libérer des injonctions, des normes et tout ce qui nous empêche d'être pleinement libres et nous-mêmes….ces ateliers peuvent-être  en mixité ou non-mixité et nous donne des outils pour nous donner confiance, nous  questionner et nous libérer des conditionnements intériorisés.</p>

      <h3> LES RETRAITES</h3>

        <p> Au sein d’un lieu ressourçant dans la nature et non loin de Paris, je propose des week-ends alliant bien-être, coaching et un cadre de réfléxion sur le thème du moment. On y repart avec plein d’idées et d’energies créatives !</p>
      <div className='cards-btns'>
        <Button className='btns' buttonStyle='btn--outline' buttonSize='btn--large'>
          Book
        </Button>
      </div>
      <CardItem src="" text="" label='yoga' path='/event'/>
    </div>
  )
}

export default Cards;
